// Left rotation on node x in tree T
LEFT-ROTATE(T, x):
  y = x.right           // y is x's right child
  x.right = y.left      // turn y's left subtree into x's right subtree
  if y.left != T.nil:
    y.left.parent = x
  y.parent = x.parent   // link x's parent to y
  if x.parent == T.nil:
    T.root = y
  else if x == x.parent.left:
    x.parent.left = y
  else:
    x.parent.right = y
  y.left = x            // put x on y's left
  x.parent = y

// Right rotation on node y in tree T (symmetric)
RIGHT-ROTATE(T, y):
  x = y.left
  y.left = x.right
  if x.right != T.nil:
    x.right.parent = y
  x.parent = y.parent
  if y.parent == T.nil:
    T.root = x
  else if y == y.parent.right:
    y.parent.right = x
  else:
    y.parent.left = x
  x.right = y
  y.parent = x
