struct RBNode {
    int key;
    bool isRed;   // true = red, false = black
    RBNode* parent;
    RBNode* left;
    RBNode* right;
};

struct RBTree {
    RBNode* nil;   // sentinel — all leaves point here
    RBNode* root;
    RBTree() {
        nil = new RBNode{0, false, nullptr, nullptr, nullptr};
        root = nil;
    }
};

void leftRotate(RBTree& T, RBNode* x) {
    RBNode* y = x->right;           // y = x's right child
    x->right = y->left;             // move y's left subtree to x's right
    if (y->left != T.nil)
        y->left->parent = x;
    y->parent = x->parent;          // link y to x's parent
    if (x->parent == T.nil)
        T.root = y;
    else if (x == x->parent->left)
        x->parent->left = y;
    else
        x->parent->right = y;
    y->left = x;                    // x goes on y's left
    x->parent = y;
}

void rightRotate(RBTree& T, RBNode* y) {
    RBNode* x = y->left;
    y->left = x->right;
    if (x->right != T.nil)
        x->right->parent = y;
    x->parent = y->parent;
    if (y->parent == T.nil)
        T.root = x;
    else if (y == y->parent->right)
        y->parent->right = x;
    else
        y->parent->left = x;
    x->right = y;
    y->parent = x;
}
