void rbInsert(RBTree& T, int key) {
    RBNode* z = new RBNode{key, true, T.nil, T.nil, T.nil};
    RBNode* y = T.nil;
    RBNode* x = T.root;

    // Phase 1: BST insert
    while (x != T.nil) {
        y = x;
        x = (z->key < x->key) ? x->left : x->right;
    }
    z->parent = y;
    if (y == T.nil)          T.root = z;
    else if (z->key < y->key) y->left  = z;
    else                      y->right = z;

    // Phase 2: fixup
    rbInsertFixup(T, z);
}

void rbInsertFixup(RBTree& T, RBNode* z) {
    while (z->parent->isRed) {
        if (z->parent == z->parent->parent->left) {
            RBNode* y = z->parent->parent->right; // uncle
            if (y->isRed) {                        // Case 1
                z->parent->isRed         = false;
                y->isRed                 = false;
                z->parent->parent->isRed = true;
                z = z->parent->parent;
            } else {
                if (z == z->parent->right) {       // Case 2
                    z = z->parent;
                    leftRotate(T, z);
                }
                z->parent->isRed         = false; // Case 3
                z->parent->parent->isRed = true;
                rightRotate(T, z->parent->parent);
            }
        } else {
            // Symmetric: parent is right child
            RBNode* y = z->parent->parent->left;  // uncle
            if (y->isRed) {
                z->parent->isRed         = false;
                y->isRed                 = false;
                z->parent->parent->isRed = true;
                z = z->parent->parent;
            } else {
                if (z == z->parent->left) {
                    z = z->parent;
                    rightRotate(T, z);
                }
                z->parent->isRed         = false;
                z->parent->parent->isRed = true;
                leftRotate(T, z->parent->parent);
            }
        }
    }
    T.root->isRed = false;
}
