// Replace subtree rooted at u with subtree rooted at v
void rbTransplant(RBTree& T, RBNode* u, RBNode* v) {
    if (u->parent == T.nil)       T.root = v;
    else if (u == u->parent->left) u->parent->left  = v;
    else                           u->parent->right = v;
    v->parent = u->parent;
}

RBNode* treeMinimum(RBTree& T, RBNode* x) {
    while (x->left != T.nil) x = x->left;
    return x;
}

void rbDeleteFixup(RBTree& T, RBNode* x) {
    while (x != T.root && !x->isRed) {
        if (x == x->parent->left) {
            RBNode* w = x->parent->right;
            if (w->isRed) {                             // Case 1
                w->isRed = false;
                x->parent->isRed = true;
                leftRotate(T, x->parent);
                w = x->parent->right;
            }
            if (!w->left->isRed && !w->right->isRed) { // Case 2
                w->isRed = true;
                x = x->parent;
            } else {
                if (!w->right->isRed) {                 // Case 3
                    w->left->isRed = false;
                    w->isRed = true;
                    rightRotate(T, w);
                    w = x->parent->right;
                }
                w->isRed = x->parent->isRed;            // Case 4
                x->parent->isRed = false;
                w->right->isRed  = false;
                leftRotate(T, x->parent);
                x = T.root;
            }
        } else {
            // Symmetric: x is right child
            RBNode* w = x->parent->left;
            if (w->isRed) {
                w->isRed = false;
                x->parent->isRed = true;
                rightRotate(T, x->parent);
                w = x->parent->left;
            }
            if (!w->right->isRed && !w->left->isRed) {
                w->isRed = true;
                x = x->parent;
            } else {
                if (!w->left->isRed) {
                    w->right->isRed = false;
                    w->isRed = true;
                    leftRotate(T, w);
                    w = x->parent->left;
                }
                w->isRed = x->parent->isRed;
                x->parent->isRed = false;
                w->left->isRed   = false;
                rightRotate(T, x->parent);
                x = T.root;
            }
        }
    }
    x->isRed = false;
}

void rbDelete(RBTree& T, RBNode* z) {
    RBNode* y = z;
    RBNode* x;
    bool yOriginallyRed = y->isRed;

    if (z->left == T.nil) {
        x = z->right;
        rbTransplant(T, z, z->right);
    } else if (z->right == T.nil) {
        x = z->left;
        rbTransplant(T, z, z->left);
    } else {
        y = treeMinimum(T, z->right);
        yOriginallyRed = y->isRed;
        x = y->right;
        if (y->parent == z) {
            x->parent = y;
        } else {
            rbTransplant(T, y, y->right);
            y->right = z->right;
            y->right->parent = y;
        }
        rbTransplant(T, z, y);
        y->left = z->left;
        y->left->parent = y;
        y->isRed = z->isRed;
    }
    if (!yOriginallyRed)
        rbDeleteFixup(T, x);
    delete z;
}
